import { notFound } from 'next/navigation';
import type { Metadata } from 'next';
import { getAllSlugs, getPostBySlug } from '@/lib/blog';
import { ShareButtons } from '@/components/ShareButtons';
import { BlogCTA } from '@/components/BlogCTA';
import { JsonLd } from '@/components/JsonLd';

export async function generateStaticParams() {
  const slugs = await getAllSlugs();
  return slugs.map(slug => ({ slug }));
}

export async function generateMetadata({ params }: { params: { slug: string } }): Promise<Metadata> {
  const post = await getPostBySlug(params.slug);
  if (!post) return {};
  return {
    title: post.title,
    description: post.description,
    openGraph: {
      title: post.title,
      description: post.description,
      type: 'article',
      publishedTime: post.date,
      authors: [post.author],
    },
  };
}

export default async function BlogPostPage({ params }: { params: { slug: string } }) {
  const post = await getPostBySlug(params.slug);
  if (!post) notFound();

  return (
    <article style={{ maxWidth: '720px', margin: '0 auto', padding: '80px 24px 96px' }}>
      <JsonLd data={{
        '@context': 'https://schema.org',
        '@type': 'Article',
        headline: post.title,
        author: { '@type': 'Person', name: post.author },
        datePublished: post.date,
        description: post.description,
        publisher: { '@type': 'Organization', name: 'DÉDALO · Arquitectura de Protección' },
      }} />

      {/* Header */}
      <header style={{ marginBottom: '48px' }}>
        <span style={{ fontSize: '11px', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase', color: post.categoryColor }}>{post.category}</span>
        <h1 style={{ fontSize: 'clamp(28px, 4vw, 44px)', fontWeight: 800, color: 'var(--text)', lineHeight: 1.2, letterSpacing: '-0.02em', marginTop: '12px', marginBottom: '16px' }}>{post.title}</h1>
        <div style={{ display: 'flex', gap: '16px', fontSize: '13px', color: 'var(--muted)' }}>
          <span>{post.author}</span>
          <span>·</span>
          <span>{new Date(post.date).toLocaleDateString('es-MX', { year: 'numeric', month: 'long', day: 'numeric' })}</span>
          <span>·</span>
          <span>{post.readTime} lectura</span>
        </div>
      </header>

      {/* Imagen de portada placeholder */}
      <div style={{ width: '100%', aspectRatio: '16/7', background: 'linear-gradient(135deg, var(--surface), var(--card))', borderRadius: '12px', marginBottom: '48px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--border)' }}>
        <span style={{ fontSize: '48px', opacity: 0.3 }}>📝</span>
      </div>

      {/* Contenido MDX */}
      <div className="prose-dedalo">{/* MDX content aquí */}</div>

      <ShareButtons title={post.title} url={`https://dedaloproteccion.mx/blog/${params.slug}`} />
